        DataOutputStream out = new DataOutputStream(s.getOutputStream()); //here we get the outputstream from our socket s to send data back    		      			         	 					 ​                                          	       	              .	.                          C-C_A   A07                  AuthFailure,    R: (.)..
        BufferedReader reader = new BufferedReader(new InputStreamReader(s.getInputStream())); //here we get the input stream from our socket s to read data    		      			         	 					 ​                                          	       	. .                           C-C_A   A07                  AuthFailure,    R: (.)..
        String message = reader.readLine();// Reading a line of text entered by client using the input stream        				                         	                           	   		      			         	 					 ​                                          	       	. .                           C-C_A   A07                  AuthFailure,    R: (.)..
        System.out.println("Client Message : " + message); // Printing a received client's input using the output stream        				                         	                           	   		      			         	 					 ​                                          	       	. .                           C-C_A   A07                  AuthFailure,    R: (.)..
        s.close();// Closing socket on both ends of connection when data transfer is done using the output stream        				                        	                           	   		      			         					 ​                                          	       	. .                           C-C_A   A07                  AuthFailure,    R: (.)..
        server.close();// Closing Server Socket once no more clients will be connected on this socket to free up resources        				                        	                           	   		      			         					 ​                                          	       	. .                           C-C_A   A07                  AuthFailure,    R: (.)..
